sql:
SELECT domain, COUNT(*) AS organism_count
FROM organisms
GROUP BY domain;

SELECT sequence
FROM genomic_data
WHERE organism_id = (SELECT organism_id FROM proteomic_data WHERE proteomic_data_id = 1);

SELECT organism_id, sequence, file_format
FROM genomic_data
WHERE organism_id = 0;

SELECT o.name, o.common_name, o.taxonomy_id
FROM organisms o
WHERE o.organism_id IN (
    SELECT organism_id FROM genomic_data
) AND o.organism_id IN (
    SELECT organism_id FROM proteomic_data
);

external_knowledge:
- 'Trailblazers' refers to the researchers who have performed the most recent analysis; 
- 'Ventured into' denotes the performance of analysis; 
- The three mentioned domains ('Archaea', 'Bacteria', 'Eukarya') represent the primary categories of organisms; 
- 'BLAST' and 'multiple sequence alignment' are types of analysis performed on organisms.

sql:
SELECT COUNT(*) AS num_organisms
FROM organisms
WHERE domain = 'Bacteria';
